      z.object({
        id: z.number(),
        tax: z.number().optional(),
        tip: z.number().optional(),
        gratuity: z.number().optional(),
        tip_after_tax: z.boolean().optional(),
        image_visibility: z.enum(['public', 'owner_only']).optional(),
