1	import { createClerkClient } from '@clerk/backend';
2	import { serve } from '@hono/node-server';
3	import { mustGetMutator, mustGetQuery } from '@rocicorp/zero';
4	import { handleMutateRequest, handleQueryRequest } from '@rocicorp/zero/server';
5	import { Hono } from 'hono';
6	
7	import { dbProvider } from './db-provider.js';
8	import { mutators } from './mutators.js';
9	import { queries } from './queries.js';
10	import { schema } from './schema.js';
11	
12	const BUILD_VERSION = process.env.BUILD_VERSION || 'unknown';
13	
14	// Structured logging utility
15	interface LogContext {
16	  requestId?: string;
17	  queryName?: string;
18	  mutatorName?: string;
19	  method?: string;
20	  path?: string;
21	  statusCode?: number;
22	  duration?: number;
23	  userID?: string;
24	  [key: string]: unknown;
25	}
26	
27	function log(
28	  level: 'info' | 'error' | 'warn' | 'debug',
29	  message: string,
30	  context: LogContext = {}
31	) {
32	  const logEntry = {
33	    timestamp: new Date().toISOString(),
34	    level,
35	    message,
36	    version: BUILD_VERSION,
37	    ...context,
38	  };
39	  const logLine = JSON.stringify(logEntry);
40	
41	  switch (level) {
42	    case 'error':
43	      console.error(logLine);
44	      break;
45	    case 'warn':
46	      console.warn(logLine);
47	      break;
48	    case 'debug':
49	      console.debug(logLine);
50	      break;
51	    default:
52	      console.log(logLine);
53	  }
54	}
55	
56	function generateRequestId(): string {
57	  // crypto.randomUUID() is available as a global in Node.js 19+
58	  // For render.com which uses Node.js 20+, this will work
59	  // @ts-ignore - crypto is a global in Node.js 19+
60	  return crypto.randomUUID();
61	}
62	
63	type AppContext = {
64	  Variables: {
65	    requestId: string;
66	    startTime: number;
67	  };
68	};
69	
70	const app = new Hono<AppContext>();
71	
72	// Validate Clerk environment variables
73	const CLERK_SECRET_KEY = process.env.CLERK_SECRET_KEY;
74	const CLERK_PUBLISHABLE_KEY = process.env.CLERK_PUBLISHABLE_KEY;
75	
76	if (!CLERK_SECRET_KEY) {
77	  const errorMessage =
78	    'Missing required Clerk environment variable: CLERK_SECRET_KEY. Add it to your .env file (see .env.example for reference).';
79	  log('error', errorMessage);
80	  throw new Error(errorMessage);
81	}
82	
83	if (!CLERK_PUBLISHABLE_KEY) {
84	  const errorMessage =
85	    'Missing required Clerk environment variable: CLERK_PUBLISHABLE_KEY. Add it to your .env file (see .env.example for reference).';
86	  log('error', errorMessage);
87	  throw new Error(errorMessage);
88	}
89	
90	// Initialize Clerk client
91	const clerkClient = createClerkClient({
92	  secretKey: CLERK_SECRET_KEY,
93	  publishableKey: CLERK_PUBLISHABLE_KEY,
94	});
95	
96	// Parse authorized parties from CLERK_AUTHORIZED_PARTIES
97	// This must be non-empty to ensure azp validation is always enforced
98	const CLERK_AUTHORIZED_PARTIES = process.env.CLERK_AUTHORIZED_PARTIES;
99	
100	if (!CLERK_AUTHORIZED_PARTIES) {
101	  const errorMessage =
102	    'Missing required environment variable: CLERK_AUTHORIZED_PARTIES. This must be set to a comma-separated list of allowed origins for Clerk azp validation. Add it to your .env file.';
103	  log('error', errorMessage);
104	  throw new Error(errorMessage);
105	}
106	
107	const authorizedParties = CLERK_AUTHORIZED_PARTIES.split(',')
108	  .map((o) => o.trim())
109	  .filter(Boolean);
110	
111	if (authorizedParties.length === 0) {
112	  const errorMessage =
113	    'CLERK_AUTHORIZED_PARTIES must contain at least one valid origin. The current value results in an empty allowlist, which would disable Clerk azp validation. Please provide a comma-separated list of allowed origins.';
114	  log('error', errorMessage);
115	  throw new Error(errorMessage);
116	}
117	
118	// Request logging middleware
119	app.use('*', async (c, next) => {
120	  const requestId = generateRequestId();
121	  const startTime = Date.now();
122	  const method = c.req.method;
123	  const path = c.req.path;
124	
125	  // Store request ID and start time in context for use in route handlers
126	  c.set('requestId', requestId);
127	  c.set('startTime', startTime);
128	
129	  log('info', 'Request started', {
130	    requestId,
131	    method,
132	    path,
133	    url: c.req.url,
134	  });
135	
136	  await next();
137	
138	  const duration = Date.now() - startTime;
139	  const statusCode = c.res.status;
140	
141	  log('info', 'Request completed', {
142	    requestId,
143	    method,
144	    path,
145	    statusCode,
146	    duration,
147	  });
148	});
149	
150	app.get('/health', (c) => {
151	  return c.json({
152	    status: 'ok',
153	    version: BUILD_VERSION,
154	    timestamp: new Date().toISOString(),
155	  });
156	});
157	
158	app.post('/api/query', async (c) => {
159	  const requestId = c.get('requestId');
160	  const startTime = c.get('startTime');
161	  let queryName: string | undefined;
162	  let userID = 'anon';
163	
164	  try {
165	    const { toAuth } = await clerkClient.authenticateRequest(c.req.raw, {
166	      authorizedParties,
167	    });
168	
169	    const auth = toAuth();
170	    userID = auth?.userId ?? 'anon';
171	
172	    const result = await handleQueryRequest(
173	      (name, args) => {
174	        queryName = name;
175	        log('debug', 'Executing query', {
176	          requestId,
177	          queryName,
178	          userID,
179	        });
180	
181	        const query = mustGetQuery(queries, name);
182	        return query.fn({ args, ctx: { userID } });
183	      },
184	      schema,
185	      c.req.raw
186	    );
187	
188	    const duration = Date.now() - startTime;
189	
190	    log('info', 'Query executed successfully', {
191	      requestId,
192	      queryName,
193	      duration,
194	      userID,
195	    });
196	
197	    return c.json(result);
198	  } catch (error) {
