import { useAuth } from '@clerk/clerk-react';
import { Trans, useLingui } from '@lingui/react/macro';
import { useZero } from '@rocicorp/zero/react';
import { useAtomValue } from 'jotai';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';

import { BillBreakdownView } from '@/features/bill-split/components/BillBreakdownView';
import {
  assignedUsersAtom,
  personFairTotalsAtom,
  personPaidStatusAtom,
  personPretaxTotalsAtom,
  receiptAtom,
  receiptTotalAtom,
  useEqualSplitAtom,
} from '@/features/receipt-collab/atoms/receiptAtoms';
import { getUserDisplayName } from '@/utils/user-display';
import { mutators } from '@/zero/mutators';

export const BillBreakdownCollab = () => {
  const { t } = useLingui();
  const { userId: clerkUserId } = useAuth();
  const zero = useZero();
  const navigate = useNavigate();
  const assignedUsers = useAtomValue(assignedUsersAtom);
  const receipt = useAtomValue(receiptAtom);
  const personFairTotals = useAtomValue(personFairTotalsAtom);
  const personPretaxTotals = useAtomValue(personPretaxTotalsAtom);
  const receiptTotal = useAtomValue(receiptTotalAtom);
  const useEqualSplit = useAtomValue(useEqualSplitAtom);
  const personPaidStatus = useAtomValue(personPaidStatusAtom);

  if (!receipt) {
    return null;
  }

  const people = assignedUsers.map((a) => ({
    id: a.receiptUserId,
    displayName: getUserDisplayName(a),
  }));

  let linkedToSignedInUserReceiptUserId: string | null = null;
  if (clerkUserId != null) {
    const claimedBySignedInUser = assignedUsers.find(
      (a) => a.receiptUser?.user?.authUserId === clerkUserId
    );
    linkedToSignedInUserReceiptUserId =
      claimedBySignedInUser?.receiptUserId ?? null;
  }

  const handleTogglePaid = async (
    receiptUserId: string,
    currentlyPaid: boolean
  ) => {
    try {
      const result = zero.mutate(
        mutators.receiptUsers.updatePaidStatus({
          id: receiptUserId,
          paid_at: currentlyPaid ? null : Date.now(),
        })
      );
      const clientResult = await result.client;
      if (clientResult.type === 'error') {
        toast.error(t`Failed to update payment status`);
      }
    } catch {
      toast.error(t`Failed to update payment status`);
    }
  };

  const handleSoftDelete = async () => {
    try {
      const result = zero.mutate(
        mutators.receipts.softDelete({ id: receipt.id })
      );
      const clientResult = await result.client;
      if (clientResult.type === 'error') {
        toast.error(t`Failed to delete receipt`);
        return;
      }
      navigate('/', { replace: true });
    } catch {
      toast.error(t`Failed to delete receipt`);
    }
  };

  return (
    <BillBreakdownView
      people={people}
      receipt={receipt}
      personFairTotals={personFairTotals}
      personPretaxTotals={personPretaxTotals}
      receiptTotal={receiptTotal}
      useEqualSplit={useEqualSplit}
      linkedToSignedInUserReceiptUserId={linkedToSignedInUserReceiptUserId}
      personPaidStatus={personPaidStatus}
      onTogglePaid={handleTogglePaid}
      onSoftDelete={handleSoftDelete}
    />
  );
};

import { useZero } from '@rocicorp/zero/react';
import { useAtomValue } from 'jotai';
import { useState } from 'react';
import { ulid } from 'ulid';

import type {
  DeleteLineItemData,
  MutationCallbackOptions,
  UpdateLineItemData,
} from '@/features/line-items/types';
import {
  planAddRebalance,
  planRemoveRebalance,
  type SiblingShareUpdate,
} from '@/features/line-items/utils/rebalance-shares';
import {
  receiptAtom,
  receiptIdAtom,
} from '@/features/receipt-collab/atoms/receiptAtoms';
import { mutators } from '@/zero/mutators';

export function useLineItemMutations() {
  const zero = useZero();
  const receipt = useAtomValue(receiptAtom);
  const receiptId = useAtomValue(receiptIdAtom);
  const [isDeleting, setIsDeleting] = useState(false);

  /**
   * Generate a unique ID for new database records using ULID.
   * ULID provides:
   * - Time-ordered IDs (better for database indexing)
   * - URL-safe encoding (base32)
   * - 128-bit entropy (extremely low collision risk)
   * - Lexicographically sortable
   */
  const generateId = (): string => {
    return ulid();
  };

  const applySiblingUpdates = async (updates: SiblingShareUpdate[]) => {
    const results = await Promise.all(
      updates.map((update) => zero.mutate(mutators.assignments.update(update)).client)
    );
    for (const result of results) {
      if (result.type === 'error') {
        console.error(
          'Failed to apply sibling rebalance update:',
          result.error.message
        );
      }
    }
  };

  /**
   * Add an assignment for an existing receipt user to a line item.
   */
  const addExistingPersonAssignment = async (
    itemId: string,
    receiptUserId: string
  ) => {
    if (!receipt) {
      return;
    }

    const lineItem = receipt.lineItems.find((item) => item.id === itemId);
    if (!lineItem) {
      console.error(`Line item with id ${itemId} not found`);
      return;
    }

    // Check if assignment already exists
    const existingAssignment = lineItem.assignments.find(
      (a) => a.receiptUserId === receiptUserId && !a.deletedAt
    );
    if (existingAssignment) {
      console.info('Assignment already exists');
      return;
    }

    const assignmentId = generateId();
    const activeSiblings = lineItem.assignments.filter((a) => !a.deletedAt);
    const rebalance = planAddRebalance(activeSiblings);

    const result = zero.mutate(
      mutators.assignments.insert({
        id: assignmentId,
        receipt_user_id: receiptUserId,
        receipt_line_item_id: itemId,
        share_percentage: rebalance ? rebalance.newcomerShare : null,
        locked: rebalance ? rebalance.newcomerLocked : false,
      })
    );

    const clientResult = await result.client;
    if (clientResult.type === 'error') {
      console.error('Failed to create assignment:', clientResult.error.message);
      return;
    }
    console.info('Successfully created assignment');

    if (rebalance) {
      await applySiblingUpdates(rebalance.siblingUpdates);
    }
  };

  /**
   * Add an assignment for a new receipt user (by display name) to a line item.
   * Creates the receipt_user first, then creates the assignment.
   */
  const addNewPersonAssignment = async (
    itemId: string,
    displayName: string
  ) => {
    if (!receipt) {
      return;
    }

    const lineItem = receipt.lineItems.find((item) => item.id === itemId);
    if (!lineItem) {
      console.error(`Line item with id ${itemId} not found`);
      return;
    }

    const receiptUserId = generateId();
    const assignmentId = generateId();

    // First, create the receipt_user
    const receiptUserResult = zero.mutate(
      mutators.receiptUsers.insert({
        id: receiptUserId,
        display_name: displayName,
      })
    );

    const receiptUserClientResult = await receiptUserResult.client;
    if (receiptUserClientResult.type === 'error') {
      console.error(
        'Failed to create receipt user:',
        receiptUserClientResult.error.message
      );
      return;
    }

    // Then, create the assignment
    const activeSiblings = lineItem.assignments.filter((a) => !a.deletedAt);
    const rebalance = planAddRebalance(activeSiblings);

    const assignmentResult = zero.mutate(
      mutators.assignments.insert({
        id: assignmentId,
        receipt_user_id: receiptUserId,
        receipt_line_item_id: itemId,
        share_percentage: rebalance ? rebalance.newcomerShare : null,
        locked: rebalance ? rebalance.newcomerLocked : false,
      })
    );

    const assignmentClientResult = await assignmentResult.client;
    if (assignmentClientResult.type === 'error') {
      console.error(
        'Failed to create assignment:',
        assignmentClientResult.error.message
      );
      // Rollback: soft-delete the orphaned receipt_user
      try {
        const rollbackResult = zero.mutate(
          mutators.receiptUsers.delete({ id: receiptUserId })
        );
        const rollbackClientResult = await rollbackResult.client;
        if (rollbackClientResult.type === 'error') {
          console.error(
            'Failed to rollback receipt user:',
            rollbackClientResult.error.message
          );
        }
      } catch (rollbackError) {
        console.error('Error during receipt user rollback:', rollbackError);
      }
    } else {
      console.info('Successfully created receipt user and assignment');
      if (rebalance) {
        await applySiblingUpdates(rebalance.siblingUpdates);
      }
    }
  };

  /**
   * Remove an assignment from a line item.
   */
  const removePersonAssignment = async (
    itemId: string,
    assignmentId: string
  ) => {
    if (!receipt) {
      return;
    }

    const lineItem = receipt.lineItems.find((item) => item.id === itemId);
    if (!lineItem) {
      console.error(`Line item with id ${itemId} not found`);
      return;
    }

    const removed = lineItem.assignments.find((a) => a.id === assignmentId);
    const remainingActive = lineItem.assignments.filter(
      (a) => a.id !== assignmentId && !a.deletedAt
    );

    const result = zero.mutate(
      mutators.assignments.delete({ id: assignmentId })
    );

    const clientResult = await result.client;
    if (clientResult.type === 'error') {
      console.error('Failed to delete assignment:', clientResult.error.message);
      return;
    }
    console.info('Successfully deleted assignment');

    if (removed) {
      const updates = planRemoveRebalance(removed, remainingActive);
      if (updates) {
        await applySiblingUpdates(updates);
      }
    }
  };

  const handleUpdateLineItem = async (data: UpdateLineItemData) => {
    const current = receipt?.lineItems.find((item) => item.id === data.itemId);
    const nextQuantity = data.quantity ?? current?.quantity.toNumber() ?? 1;
    const nextPricePerItem =
      data.price_per_item ?? current?.pricePerItem.toNumber() ?? 0;
    const nextTotalPrice =
      Math.round(nextQuantity * nextPricePerItem * 100) / 100;

    const result = zero.mutate(
      mutators.lineItems.update({
        id: data.itemId,
        name: data.name,
        quantity: data.quantity,
        price_per_item: data.price_per_item,
        total_price: nextTotalPrice,
      })
    );

    const clientResult = await result.client;

    if (clientResult.type === 'error') {
      console.error('Failed to update line item:', clientResult.error.message);
    } else {
      console.info('Successfully updated line item');
    }
  };

  const handleDeleteLineItem = async (
    data: DeleteLineItemData,
    options?: MutationCallbackOptions
  ) => {
    setIsDeleting(true);
    try {
      const result = zero.mutate(
        mutators.lineItems.delete({
          id: data.itemId,
        })
      );

      const clientResult = await result.client;

      if (clientResult.type === 'error') {
        console.error(
          'Failed to delete line item:',
          clientResult.error.message
        );
        options?.onError?.(new Error(clientResult.error.message));
      } else {
        console.info('Successfully deleted line item');
        options?.onSuccess?.();
      }
    } finally {
      setIsDeleting(false);
    }
  };

  return {
    addExistingPersonAssignment,
    addNewPersonAssignment,
    removePersonAssignment,
    handleUpdateLineItem,
    handleDeleteLineItem,
    receipt,
    receiptId,
    isReady: !!receipt && !!receiptId,
    isDeleting,
  };
}

import { useZero } from '@rocicorp/zero/react';
import { useState } from 'react';

import { mutators } from '@/zero/mutators';

interface ReceiptUpdateArgs {
  id: number;
  tip?: number;
  gratuity?: number;
  tip_after_tax?: boolean;
}

interface UseReceiptMutationOptions {
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

interface UseReceiptMutationReturn {
  mutate: (args: ReceiptUpdateArgs) => Promise<void>;
  isSaving: boolean;
}

/**
 * Custom hook that encapsulates the common pattern for receipt mutations using Zero.
 * Handles loading state, error handling, and result processing.
 *
 * @param options - Optional callbacks for success and error handling
 * @returns Object with mutate function and isSaving state
 *
 * @example
 * ```tsx
 * const { mutate, isSaving } = useReceiptMutation({
 *   onSuccess: () => setIsEditing(false),
 *   onError: (error) => console.error('Failed:', error)
 * });
 *
 * await mutate({ id: receiptId, tip: 10.0 });
 * ```
 */
export function useReceiptMutation(
  options?: UseReceiptMutationOptions
): UseReceiptMutationReturn {
  const zero = useZero();
  const [isSaving, setIsSaving] = useState(false);

  const mutate = async (args: ReceiptUpdateArgs) => {
    if (args.id === undefined || args.id === null) {
      const error = new Error('Receipt ID is required');
      console.error(error.message);
      options?.onError?.(error);
      return;
    }

    setIsSaving(true);
    try {
      const result = zero.mutate(mutators.receipts.update(args));

      const clientResult = await result.client;

      if (clientResult.type === 'error') {
        const error = new Error(clientResult.error.message);
        console.error('Failed to update receipt:', error.message);
        options?.onError?.(error);
      } else {
        console.info('Successfully updated receipt');
        options?.onSuccess?.();
      }
    } catch (error) {
      const err = error instanceof Error ? error : new Error(String(error));
      console.error('Error updating receipt:', err);
      options?.onError?.(err);
    } finally {
      setIsSaving(false);
    }
  };

  return { mutate, isSaving };
}

import { Trans } from '@lingui/react/macro';
import { useZero } from '@rocicorp/zero/react';
import Decimal from 'decimal.js';
import { useAtomValue } from 'jotai';
import { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';

import LineItemForm from '@/components/Receipt/LineItemForm';
import { Button } from '@/components/ui/button';
import type { UpdateLineItemData } from '@/features/line-items/types';
import { receiptIdAtom } from '@/features/receipt-collab/atoms/receiptAtoms';
import type { ReceiptLineItem } from '@/models/ReceiptLineItem';
import { mutators } from '@/zero/mutators';

function isStringEmpty(str: string) {
  return str == null || str.trim() === '';
}

export default function LineItemAddForm({
  onAddCancel,
}: {
  onAddCancel: () => void;
}) {
  const zero = useZero();
  const receiptId = useAtomValue(receiptIdAtom);
  const [isPending, setIsPending] = useState(false);

  // Local state for form values with default values
  const [formData, setFormData] = useState({
    name: '',
    quantity: 1,
    price_per_item: 0,
  });

  const handleAddItem = async () => {
    if (!receiptId) {
      console.error('Cannot add line item: receiptId is missing');
      return;
    }

    setIsPending(true);

    try {
      const id = uuidv4();
      const quantity = formData.quantity ?? 1;
      const pricePerItem = formData.price_per_item ?? 0;
      const totalPrice = quantity * pricePerItem;

      const result = zero.mutate(
        mutators.lineItems.insert({
          id,
          receipt_id: Number(receiptId),
          name: formData.name,
          quantity,
          price_per_item: pricePerItem,
          total_price: totalPrice,
          created_at: Date.now(),
        })
      );

      const clientResult = await result.client;

      if (clientResult.type === 'error') {
        console.error('Failed to add line item:', clientResult.error.message);
      } else {
        console.info('Successfully added line item');
        onAddCancel();
      }
    } finally {
      setIsPending(false);
    }
  };

  const handleNameChange = (name: string) => {
    setFormData((prev) => ({ ...prev, name }));
  };

  const handleQuantityChange = (quantity: number) => {
    setFormData((prev) => ({
      ...prev,
      quantity,
    }));
  };

  // Create a mutate function that updates local state instead of calling the API
  const mutate = (data: UpdateLineItemData) => {
    // Update local state based on what field changed
    if ('price_per_item' in data) {
      setFormData((prev) => ({
        ...prev,
        price_per_item: data.price_per_item || 0,
      }));
    }
    if ('quantity' in data) {
      setFormData((prev) => ({
        ...prev,
        quantity: data.quantity || 1,
      }));
    }
    if ('name' in data) {
      setFormData((prev) => ({
        ...prev,
        name: data.name || '',
      }));
    }
  };

  // Create a temporary ReceiptLineItem for the form
  const tempItem: ReceiptLineItem = {
    id: 'temp', // Temporary ID for the form
    name: formData.name,
    quantity: new Decimal(formData.quantity),
    pricePerItem: new Decimal(formData.price_per_item),
    totalPrice: new Decimal(formData.quantity * formData.price_per_item),
    deletedAt: null,
    assignments: [],
  };

  if (!receiptId) {
    return null;
  }

  return (
    <div className="w-full">
      <LineItemForm
        item={tempItem}
        receiptId={receiptId}
        onNameChange={handleNameChange}
        onQuantityChange={handleQuantityChange}
        mutate={mutate}
      />

      <div className="flex justify-end gap-2 p-2">
        <Button onClick={onAddCancel} variant="outline" disabled={isPending}>
          <Trans>Cancel</Trans>
        </Button>
        <Button
          onClick={handleAddItem}
          variant="outline"
          disabled={isPending || isStringEmpty(formData.name)}
        >
          <Trans>Add</Trans>
        </Button>
      </div>
    </div>
  );
}

