interface ClaimReceiptUserDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  receiptUserId: string;
  displayName: string;
}

export function ClaimReceiptUserDialog({
  open,
  onOpenChange,
  receiptUserId,
  displayName,
}: ClaimReceiptUserDialogProps) {
  const { t } = useLingui();
  const zero = useZero();
  const [user] = useQuery(queries.users.receipts.byAuthUserId({}));
  const [isSaving, setIsSaving] = useState(false);

  const internalUserId = user?.id;
  const canClaim = open && internalUserId != null && receiptUserId.length > 0;

  const handleClaim = async () => {
    if (internalUserId == null) return;

    setIsSaving(true);
    try {
      const result = zero.mutate(
        mutators.receiptUsers.update({
          id: receiptUserId,
          user_id: internalUserId,
        })
      );

      const clientResult = await result.client;

      if (clientResult.type === 'error') {
        console.error(
          'Failed to claim receipt user:',
          clientResult.error.message
        );
        toast.error(t`Failed to claim person`, {
          description: clientResult.error.message,
        });
      } else {
        onOpenChange(false);
      }
    } catch (error) {
      const message =
        error instanceof Error ? error.message : t`Something went wrong`;
      console.error('Error claiming receipt user:', error);
      toast.error(t`Failed to claim person`, { description: message });
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>
            <Trans>Claim this person</Trans>
          </DialogTitle>
          <DialogDescription>
            <Trans>
              Claim "{displayName}" as yourself? This will link this user to
              your account.
            </Trans>
          </DialogDescription>
        </DialogHeader>
        <DialogFooter>
          <Button
            type="button"
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isSaving}
          >
            <Trans>Cancel</Trans>
          </Button>
          <Button
            type="button"
            onClick={handleClaim}
            disabled={!canClaim || isSaving}
          >
            {isSaving ? <Trans>Claiming…</Trans> : <Trans>Claim</Trans>}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { Trans, useLingui } from '@lingui/react/macro';
import { useQuery, useZero } from '@rocicorp/zero/react';
import { ArrowRight } from 'lucide-react';
import { useState } from 'react';
import { toast } from 'sonner';

import type { AvatarChipColor } from '@/components/Receipt/utils/avatar-chip-colors';
import {
  DEFAULT_CHIP_COLOR,
  getAvatarChipColors,
} from '@/components/Receipt/utils/avatar-chip-colors';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { getInitials } from '@/lib/get-initials';
import { cn } from '@/lib/utils';
import { mutators } from '@/zero/mutators';
import { queries } from '@/zero/queries';

interface SwitchReceiptUserDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  previousReceiptUser: { id: string; name: string };
  newReceiptUser: { id: string; name: string };
  /** Optional: pass receiptId + possiblePeople to derive avatar colors; otherwise defaults are used */
  receiptId?: number;
  possiblePeople?: string[];
}

/**
 * Determines whether the user is allowed to confirm the switch action.
 * All of the following must be true: dialog is open, current user is known in our system,
 * and both previous and new receipt users have valid non-empty IDs.
 *
 * @param open - Whether the dialog is currently open
 * @param internalUserId - Our internal user id (from Zero), or undefined if not loaded/synced
 * @param previousReceiptUserId - ID of the receipt user being unclaimed
 * @param newReceiptUserId - ID of the receipt user being claimed
 * @returns true if the Switch button should be enabled
 */
function canPerformSwitch(
  open: boolean,
  internalUserId: number | undefined,
  previousReceiptUserId: string,
  newReceiptUserId: string
): boolean {
  // Dialog must be visible for the action to be valid.
  if (!open) return false;
  // We need a known internal user to assign to the new receipt user.
  if (internalUserId == null) return false;
  // Both receipt user IDs must be non-empty for the unclaim/claim pair.
  if (previousReceiptUserId.length === 0) return false;
  if (newReceiptUserId.length === 0) return false;
  return true;
}

export function SwitchReceiptUserDialog({
  open,
  onOpenChange,
  previousReceiptUser,
  newReceiptUser,
  receiptId,
  possiblePeople,
}: SwitchReceiptUserDialogProps) {
  const { t } = useLingui();
  const zero = useZero();
  const [user] = useQuery(queries.users.receipts.byAuthUserId({}));
  const [isSaving, setIsSaving] = useState(false);

  const internalUserId = user?.id;

  // Derive avatar chip colors only when we have receipt scope and participant list.
  let chipColors: Map<string, AvatarChipColor> | null = null;
  if (receiptId != null && possiblePeople != null) {
    chipColors = getAvatarChipColors(receiptId, possiblePeople);
  }

  // Use scoped colors when available; otherwise fall back to default chip styling.
  const previousColor =
    chipColors?.get(previousReceiptUser.id) ?? DEFAULT_CHIP_COLOR;
  const newColor = chipColors?.get(newReceiptUser.id) ?? DEFAULT_CHIP_COLOR;

  const canSwitch = canPerformSwitch(
    open,
    internalUserId,
    previousReceiptUser.id,
    newReceiptUser.id
  );

  const handleSwitch = async () => {
    if (internalUserId == null) return;

    setIsSaving(true);
    try {
      // Step 1: Unlink our account from the previous receipt user.
      const unclaimResult = zero.mutate(
        mutators.receiptUsers.update({
          id: previousReceiptUser.id,
          user_id: null,
        })
      );
      const unclaimClient = await unclaimResult.client;
      if (unclaimClient.type === 'error') {
        console.error(
          'Failed to unclaim previous receipt user:',
          unclaimClient.error.message
        );
        toast.error(t`Failed to switch person`, {
          description: unclaimClient.error.message,
        });
        return;
      }

      // Step 2: Link our account to the new receipt user.
      const claimResult = zero.mutate(
        mutators.receiptUsers.update({
          id: newReceiptUser.id,
          user_id: internalUserId,
        })
      );
      const claimClient = await claimResult.client;
      if (claimClient.type === 'error') {
        console.error(
          'Failed to claim new receipt user:',
          claimClient.error.message
        );
        // Best-effort rollback: restore user_id on previous receipt user
        try {
          const rollbackResult = zero.mutate(
            mutators.receiptUsers.update({
              id: previousReceiptUser.id,
              user_id: internalUserId,
            })
          );
          const rollbackClient = await rollbackResult.client;
          if (rollbackClient.type === 'error') {
            console.error('Rollback failed:', rollbackClient.error.message);
            toast.error(t`Failed to switch person`, {
              description: t`Could not restore your original claim. Please try claiming again manually.`,
            });
          } else {
            toast.error(t`Failed to switch person`, {
              description: t`Your original claim has been restored.`,
            });
          }
        } catch (rollbackError) {
          console.error('Rollback threw an exception:', rollbackError);
          toast.error(t`Failed to switch person`, {
            description: t`Could not restore your original claim. Please try claiming again manually.`,
          });
        }
      } else {
        onOpenChange(false);
      }
    } catch (error) {
      const message =
        error instanceof Error ? error.message : t`Something went wrong`;
      console.error('Error switching receipt user:', error);
      toast.error(t`Failed to switch person`, { description: message });
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>
            <Trans>Switch to this person</Trans>
          </DialogTitle>
          <DialogDescription>
            <Trans>
              Move your claim from "{previousReceiptUser.name}" to "
              {newReceiptUser.name}"? Your account will be linked to the new
              receipt user.
            </Trans>
          </DialogDescription>
        </DialogHeader>
        {/* Previous and new receipt user avatars with arrow indicating the switch direction. */}
        <div className="flex items-center justify-center gap-4 py-4">
          <div className="flex flex-col items-center gap-2">
            <Avatar
              className={cn('ring-2', previousColor.ring)}
              title={previousReceiptUser.name}
            >
              <AvatarFallback
                className={cn(previousColor.bg, previousColor.text)}
              >
                {getInitials(previousReceiptUser.name)}
              </AvatarFallback>
            </Avatar>
            <span className="max-w-[100px] truncate text-center text-sm text-muted-foreground">
              {previousReceiptUser.name}
            </span>
          </div>
          <ArrowRight
            className="size-6 shrink-0 text-muted-foreground"
            aria-hidden
          />
          <div className="flex flex-col items-center gap-2">
            <Avatar
              className={cn('ring-2', newColor.ring)}
              title={newReceiptUser.name}
            >
              <AvatarFallback className={cn(newColor.bg, newColor.text)}>
                {getInitials(newReceiptUser.name)}
              </AvatarFallback>
            </Avatar>
            <span className="max-w-[100px] truncate text-center text-sm text-muted-foreground">
              {newReceiptUser.name}
            </span>
          </div>
        </div>
        <DialogFooter>
          <Button
            type="button"
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isSaving}
          >
            <Trans>Cancel</Trans>
          </Button>
          <Button
            type="button"
            onClick={handleSwitch}
            disabled={!canSwitch || isSaving}
          >
            {isSaving ? <Trans>Switching…</Trans> : <Trans>Switch</Trans>}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useZero } from '@rocicorp/zero/react';
import Decimal from 'decimal.js';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type { ReceiptLineItem } from '@/models/ReceiptLineItem';
import { getUserDisplayName } from '@/utils/user-display';
import { mutators } from '@/zero/mutators';

import {
  evenShares,
  largestRemainderRound,
  rebalance,
  type ShareEntry,
} from '@/features/assignments/utils/split-percent';

const PERSIST_DEBOUNCE_MS = 150;

/**
 * React-layer view of a single share row. Extends the pure {@link ShareEntry}
 * with display-only fields the UI needs (display name, color lookup key).
 */
export type DraftEntry = ShareEntry & {
  receiptUserId: string;
  displayName: string;
};

export type UseSplitPercentArgs = {
  item: ReceiptLineItem;
};

export type UseSplitPercentResult = {
  entries: DraftEntry[];
  roundedPercents: number[];
  handleChange: (assignmentId: string, value: Decimal) => void;
  handleToggleLock: (assignmentId: string) => void;
  handleReset: () => void;
};

/**
 * Owns the React-side orchestration for the "split by percent" tab:
 *
 *   - Seeds local draft state from the assignments coming off the receipt.
 *   - Re-seeds when the underlying assignments change (add/remove/remote update).
 *   - Debounces per-row writes back to Zero so slider drags coalesce into a
 *     single mutator call per row.
 *   - Exposes ready-to-render `entries` and `roundedPercents` plus the three
 *     handlers the view needs.
 *
 * All numerical work is delegated to the pure helpers in `../utils/split-percent`.
 */
export function useSplitPercent({
  item,
}: UseSplitPercentArgs): UseSplitPercentResult {
  const zero = useZero();

  // Only active assignments participate in the split; soft-deleted rows would
  // otherwise skew the even-share fallback and show ghost rows in the UI.
  const activeAssignments = useMemo(
    () => item.assignments.filter((assignment) => !assignment.deletedAt),
    [item.assignments]
  );

  // Build a stable key that changes whenever any assignment id, share, or
  // lock flag changes. Used to re-seed local state from the source of truth.
  const seedKey = useMemo(
    () =>
      activeAssignments
        .map(
          (assignment) =>
            `${assignment.id}:${assignment.sharePercentage?.toString() ?? 'null'}:${assignment.locked ? 1 : 0}`
        )
        .join('|'),
    [activeAssignments]
  );

  // Derive the initial draft entries from the receipt's assignments. Rows
  // without an explicit share fall back to an even split across participants.
  const seedEntries = useMemo<DraftEntry[]>(() => {
    const participantCount = activeAssignments.length;
    const fallbackShare = evenShares(participantCount);

    return activeAssignments.map((assignment) => {
      let share: Decimal;
      if (assignment.sharePercentage != null) {
        // Persisted custom share exists → honor it.
        share = assignment.sharePercentage;
      } else {
        // No persisted share yet → seed from the even-split fallback.
        share = fallbackShare;
      }

      return {
        id: assignment.id,
        receiptUserId: assignment.receiptUserId,
        displayName: getUserDisplayName(assignment),
        share,
        locked: assignment.locked,
      };
    });
  }, [activeAssignments]);

  const [entries, setEntries] = useState<DraftEntry[]>(seedEntries);

  // Re-seed whenever the upstream assignments change so remote edits and
  // add/remove operations are reflected locally.
  useEffect(() => {
    setEntries(seedEntries);
  }, [seedKey, seedEntries]);

  // Per-assignment debounce timers. Kept in a ref so re-renders don't reset
  // pending writes mid-flight.
  const persistTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
    new Map()
  );

  useEffect(() => {
    const timers = persistTimers.current;
    return () => {
      for (const timer of timers.values()) {
        clearTimeout(timer);
      }
      timers.clear();
    };
  }, []);

  const persistShare = useCallback(
    (assignmentId: string, share: Decimal) => {
      // Replace any in-flight timer for this row so rapid slider moves
      // coalesce into a single mutator call.
      const existing = persistTimers.current.get(assignmentId);
      if (existing) {
        clearTimeout(existing);
      }

      const timer = setTimeout(() => {
        void zero.mutate(
          mutators.assignments.update({
            id: assignmentId,
            share_percentage: share.toNumber(),
          })
        );
        persistTimers.current.delete(assignmentId);
      }, PERSIST_DEBOUNCE_MS);

      persistTimers.current.set(assignmentId, timer);
    },
    [zero]
  );

  const persistChangedShares = useCallback(
    (next: DraftEntry[], previous: DraftEntry[]) => {
      // Diff each row so we only schedule a write when its share actually
      // moved. Sibling rebalancing legitimately touches every unlocked row.
      for (const entry of next) {
        const prev = previous.find((candidate) => candidate.id === entry.id);
        if (!prev || !prev.share.equals(entry.share)) {
          persistShare(entry.id, entry.share);
        }
      }
    },
    [persistShare]
  );

  const handleChange = useCallback(
    (assignmentId: string, value: Decimal) => {
      setEntries((prev) => {
        // Delegate the math to the pure module and persist any row whose
        // share ended up different from its previous value.
        const next = rebalance(prev, assignmentId, value) as DraftEntry[];
        persistChangedShares(next, prev);
        return next;
      });
    },
    [persistChangedShares]
  );

  const handleToggleLock = useCallback(
    (assignmentId: string) => {
      setEntries((prev) => {
        // Flip the lock flag for the targeted row only.
        const next = prev.map((entry) => {
          if (entry.id === assignmentId) {
            return { ...entry, locked: !entry.locked };
          }
          return entry;
        });

        // Mirror the new lock state to Zero so it persists.
        const target = next.find((entry) => entry.id === assignmentId);
        if (target) {
          void zero.mutate(
            mutators.assignments.update({
              id: assignmentId,
              locked: target.locked,
            })
          );
        }

        return next;
      });
    },
    [zero]
  );

  const handleReset = useCallback(() => {
    setEntries((prev) => {
      // Reset: every row gets the even share and every lock is cleared.
      const share = evenShares(prev.length);
      const next = prev.map((entry) => ({
        ...entry,
        share,
        locked: false,
      }));

      // Fire-and-forget a write for every row so the persisted state matches
      // what the user sees. This bypasses the debounce intentionally — a
      // reset is a single discrete action, not a drag.
      const sharePercentage = share.toNumber();
      for (const entry of next) {
        // Cancel any pending debounced write so it can't clobber this reset.
        const pending = persistTimers.current.get(entry.id);
        if (pending) {
          clearTimeout(pending);
          persistTimers.current.delete(entry.id);
        }
        void zero.mutate(
          mutators.assignments.update({
            id: entry.id,
            share_percentage: sharePercentage,
            locked: false,
          })
        );
      }

      return next;
    });
  }, [zero]);

  // Pre-compute the integer percents shown in the UI so the component layer
  // never has to deal with rounding math directly.
  const roundedPercents = useMemo(
    () => largestRemainderRound(entries.map((entry) => entry.share)),
    [entries]
  );

  return {
    entries,
    roundedPercents,
    handleChange,
    handleToggleLock,
    handleReset,
  };
}

import { Trans, useLingui } from '@lingui/react/macro';
import { useZero } from '@rocicorp/zero/react';
import { useState } from 'react';
import { toast } from 'sonner';

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { mutators } from '@/zero/mutators';

interface ImageSettingsDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  receiptId: number;
  imageVisibility: string | null | undefined;
}

export function ImageSettingsDialog({
  open,
  onOpenChange,
  receiptId,
  imageVisibility,
}: ImageSettingsDialogProps) {
  const { t } = useLingui();
  const zero = useZero();
  const [isSaving, setIsSaving] = useState(false);
  const isPrivate = imageVisibility === 'owner_only';

  const handleVisibilityToggle = async (checked: boolean) => {
    setIsSaving(true);

    try {
      const newVisibility = checked ? 'owner_only' : 'public';

      const result = zero.mutate(
        mutators.receipts.update({
          id: receiptId,
          image_visibility: newVisibility,
        })
      );

      const clientResult = await result.client;

      if (clientResult.type === 'error') {
        console.error(
          'Failed to update image visibility:',
          clientResult.error.message
        );
        toast.error(t`Failed to update image visibility`);
      } else {
        console.info('Successfully updated image visibility');
        toast.success(t`Image visibility updated`);
      }
    } catch (error) {
      console.error('Error updating image visibility:', error);
      toast.error(t`Failed to update image visibility`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>
            <Trans>Image Settings</Trans>
          </DialogTitle>
          <DialogDescription>
            <Trans>Control who can see the receipt image.</Trans>
          </DialogDescription>
        </DialogHeader>
        <div className="flex items-center justify-between space-x-2 py-4">
          <Label htmlFor="image-visibility" className="flex flex-col space-y-1">
            <span>
              <Trans>Private Image</Trans>
            </span>
            <span className="text-xs font-normal text-muted-foreground">
              <Trans>Only you can see the image when enabled</Trans>
            </span>
          </Label>
          <Switch
            id="image-visibility"
            checked={isPrivate}
            onCheckedChange={handleVisibilityToggle}
            disabled={isSaving}
          />
        </div>
      </DialogContent>
    </Dialog>
  );
}

