37	/**
38	 * Determines whether the user is allowed to confirm the switch action.
39	 * All of the following must be true: dialog is open, current user is known in our system,
40	 * and both previous and new receipt users have valid non-empty IDs.
41	 *
42	 * @param open - Whether the dialog is currently open
43	 * @param internalUserId - Our internal user id (from Zero), or undefined if not loaded/synced
44	 * @param previousReceiptUserId - ID of the receipt user being unclaimed
45	 * @param newReceiptUserId - ID of the receipt user being claimed
46	 * @returns true if the Switch button should be enabled
47	 */
48	function canPerformSwitch(
49	  open: boolean,
50	  internalUserId: number | undefined,
51	  previousReceiptUserId: string,
52	  newReceiptUserId: string
53	): boolean {
54	  // Dialog must be visible for the action to be valid.
55	  if (!open) return false;
56	  // We need a known internal user to assign to the new receipt user.
57	  if (internalUserId == null) return false;
58	  // Both receipt user IDs must be non-empty for the unclaim/claim pair.
59	  if (previousReceiptUserId.length === 0) return false;
60	  if (newReceiptUserId.length === 0) return false;
61	  return true;
62	}
63	
64	export function SwitchReceiptUserDialog({
65	  open,
66	  onOpenChange,
67	  previousReceiptUser,
68	  newReceiptUser,
69	  receiptId,
70	  possiblePeople,
71	}: SwitchReceiptUserDialogProps) {
72	  const { t } = useLingui();
73	  const zero = useZero();
74	  const [user] = useQuery(queries.users.receipts.byAuthUserId({}));
75	  const [isSaving, setIsSaving] = useState(false);
76	
77	  const internalUserId = user?.id;
78	
79	  // Derive avatar chip colors only when we have receipt scope and participant list.
80	  let chipColors: Map<string, AvatarChipColor> | null = null;
81	  if (receiptId != null && possiblePeople != null) {
82	    chipColors = getAvatarChipColors(receiptId, possiblePeople);
83	  }
84	
85	  // Use scoped colors when available; otherwise fall back to default chip styling.
86	  const previousColor =
87	    chipColors?.get(previousReceiptUser.id) ?? DEFAULT_CHIP_COLOR;
88	  const newColor = chipColors?.get(newReceiptUser.id) ?? DEFAULT_CHIP_COLOR;
89	
90	  const canSwitch = canPerformSwitch(
91	    open,
92	    internalUserId,
93	    previousReceiptUser.id,
94	    newReceiptUser.id
95	  );
96	
97	  const handleSwitch = async () => {
98	    if (internalUserId == null) return;
99	
100	    setIsSaving(true);
101	    try {
102	      // Step 1: Unlink our account from the previous receipt user.
103	      const unclaimResult = zero.mutate(
104	        mutators.receiptUsers.update({
105	          id: previousReceiptUser.id,
106	          user_id: null,
107	        })
108	      );
109	      const unclaimClient = await unclaimResult.client;
110	      if (unclaimClient.type === 'error') {
111	        console.error(
112	          'Failed to unclaim previous receipt user:',
113	          unclaimClient.error.message
114	        );
115	        toast.error(t`Failed to switch person`, {
116	          description: unclaimClient.error.message,
117	        });
118	        return;
119	      }
120	
121	      // Step 2: Link our account to the new receipt user.
122	      const claimResult = zero.mutate(
123	        mutators.receiptUsers.update({
124	          id: newReceiptUser.id,
125	          user_id: internalUserId,
126	        })
127	      );
128	      const claimClient = await claimResult.client;
129	      if (claimClient.type === 'error') {
130	        console.error(
131	          'Failed to claim new receipt user:',
132	          claimClient.error.message
133	        );
134	        // Best-effort rollback: restore user_id on previous receipt user
135	        try {
136	          const rollbackResult = zero.mutate(
137	            mutators.receiptUsers.update({
138	              id: previousReceiptUser.id,
139	              user_id: internalUserId,
140	            })
141	          );
142	          const rollbackClient = await rollbackResult.client;
143	          if (rollbackClient.type === 'error') {
144	            console.error('Rollback failed:', rollbackClient.error.message);
145	            toast.error(t`Failed to switch person`, {
146	              description: t`Could not restore your original claim. Please try claiming again manually.`,
147	            });
148	          } else {
149	            toast.error(t`Failed to switch person`, {
150	              description: t`Your original claim has been restored.`,
151	            });
152	          }
153	        } catch (rollbackError) {
154	          console.error('Rollback threw an exception:', rollbackError);
155	          toast.error(t`Failed to switch person`, {
156	            description: t`Could not restore your original claim. Please try claiming again manually.`,
157	          });
158	        }
159	      } else {
160	        onOpenChange(false);
161	      }
162	    } catch (error) {
163	      const message =
164	        error instanceof Error ? error.message : t`Something went wrong`;
165	      console.error('Error switching receipt user:', error);
166	      toast.error(t`Failed to switch person`, { description: message });
167	    } finally {
168	      setIsSaving(false);
169	    }
170	  };
171	
172	  return (
173	    <Dialog open={open} onOpenChange={onOpenChange}>
174	      <DialogContent>
